const profileRows = $('Read Profile').all().map(i => i.json);
const workoutRows = $('Read Workout Log').all().map(i => i.json);

const pad = (n) => String(n).padStart(2, '0');
const now = new Date();
const today = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;

const out = [];

for (const profile of profileRows) {
  if (!profile.chat_id) continue;
  const chat_id = profile.chat_id;
  const interval = Number(profile.training_days_interval) || 1;

  const sortedW = workoutRows
    .filter(r => r.date)
    .sort((a, b) => String(a.date).localeCompare(String(b.date)));
  const lastWorkout = sortedW[sortedW.length - 1] || null;

  function parseN(plan) {
    if (!plan) return null;
    const m = String(plan).match(/№?\s*([1-4])/);
    if (m) return Number(m[1]);
    const s = String(plan).toLowerCase();
    if (s.includes('грудь') && s.includes('бицепс')) return 1;
    if (s.includes('плечи') && s.includes('грудь'))  return 2;
    if (s.includes('спина') && s.includes('трицепс'))return 3;
    if (s.includes('ноги')) return 4;
    return null;
  }

  let expectedNum = null;
  if (!lastWorkout) {
    expectedNum = 1;
  } else {
    const lastDate = new Date(String(lastWorkout.date));
    const todayD = new Date(today);
    const daysSince = Math.floor((todayD - lastDate) / (1000*60*60*24));
    if (daysSince < interval) expectedNum = null; // отдых
    else expectedNum = ((parseN(lastWorkout.day_plan) || 0) % 4) + 1;
  }

  const todayLogged = sortedW.some(r => String(r.date) === today);
  const need_ping = expectedNum !== null && !todayLogged;

  if (need_ping) {
    const labels = {
      1: '№1 — Грудь + Бицепс',
      2: '№2 — Плечи + Грудь',
      3: '№3 — Спина + Трицепс',
      4: '№4 — Ноги',
    };
    const text = `Эй. Сегодня по циклу должна была быть тренировка ${labels[expectedNum]}, а отчёта от тебя нет. Что случилось? Завтра ты по плану отдыхаешь — лучше не пропускать.`;
    out.push({ json: { chat_id, text } });
  }
}

return out;
